export const EINSTEIN_GERADO_2026_QUESTIONS: any[] = [
  { id: "einstein_gerado26_001", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher, 29 anos de idade, G2P1, 39 semanas de gestação, em trabalho de parto ativo, apresenta desaceleração variável recorrente à cardiotocografia após rotura de membranas. Ao toque, percebe-se alça de cordão umbilical no canal vaginal, abaixo da apresentação fetal. Qual é a conduta imediata mais adequada?", options: ["Elevação manual da apresentação fetal e cesariana de urgência.", "Aguardar evolução espontânea do parto vaginal.", "Amniotomia complementar para acelerar o parto.", "Ocitocina para acelerar as contrações."], correctIndex: 0 },
  { id: "einstein_gerado26_002", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Gestante, 27 anos de idade, 12 semanas, realiza translucência nucal aumentada (4,2 mm) no ultrassom morfológico de primeiro trimestre. Qual é a conduta mais apropriada na sequência da investigação?", options: ["Aconselhamento genético e teste diagnóstico invasivo ou não invasivo conforme desejo do casal.", "Interrupção da gestação, independente de confirmação diagnóstica.", "Repetir apenas o ultrassom em 20 semanas, sem outra investigação.", "Iniciar profilaxia com ácido fólico em dose triplicada como única conduta."], correctIndex: 0 },
  { id: "einstein_gerado26_003", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher, 33 anos de idade, apresenta amenorreia secundária há 6 meses, galactorreia bilateral espontânea e cefaleia. Prolactina sérica de 180 ng/mL (referência até 25). Ressonância de sela túrcica mostra lesão hipofisária de 14 mm. Qual é o tratamento de primeira linha?", options: ["Agonista dopaminérgico (cabergolina).", "Cirurgia transesfenoidal como primeira escolha.", "Radioterapia hipofisária isolada.", "Reposição isolada de estrogênio, sem tratar a lesão hipofisária."], correctIndex: 0 },
  { id: "einstein_gerado26_004", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Gestante, 24 anos de idade, 8 semanas, apresenta sangramento vaginal discreto, cólica leve e colo uterino fechado ao exame especular. Ultrassom transvaginal confirma embrião vivo com batimentos cardíacos presentes, compatível com a idade gestacional. Qual é a conduta?", options: ["Conduta expectante com repouso relativo e reavaliação.", "Esvaziamento uterino imediato.", "Internação hospitalar obrigatória por 7 dias.", "Progesterona intramuscular em altas doses como tratamento de urgência."], correctIndex: 0 },
  { id: "einstein_gerado26_005", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher, 45 anos de idade, apresenta sangramento uterino aumentado, e biópsia de endométrio realizada por espessamento suspeito confirma hiperplasia endometrial sem atipia. Sem desejo reprodutivo. Qual é o tratamento de primeira linha?", options: ["Progestogênio (oral ou dispositivo intrauterino liberador de levonorgestrel).", "Histerectomia total imediata como primeira conduta.", "Quimioterapia sistêmica.", "Radioterapia pélvica isolada."], correctIndex: 0 },
  { id: "einstein_gerado26_006", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Gestante, 31 anos de idade, 36 semanas, refere diminuição da movimentação fetal há 2 dias. Cardiotocografia mostra padrão não reativo, sem acelerações e variabilidade reduzida. Qual é a próxima conduta na investigação do bem-estar fetal?", options: ["Perfil biofísico fetal complementar.", "Interrupção imediata da gestação sem outra avaliação.", "Repetir apenas a ausculta intermitente em casa.", "Alta com retorno em 1 semana, sem investigação adicional."], correctIndex: 0 },
  { id: "einstein_gerado26_007", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher, 26 anos de idade, nuligesta, apresenta dor pélvica aguda intensa, unilateral, após esforço físico. Ultrassom transvaginal mostra ovário aumentado com ausência de fluxo Doppler ao lado da dor. Qual é a hipótese diagnóstica e a conduta?", options: ["Torção anexial; laparoscopia de urgência para destorção.", "Cisto funcional simples; conduta expectante isolada.", "Doença inflamatória pélvica; apenas antibioticoterapia oral.", "Gravidez ectópica; metotrexato isolado, sem cirurgia."], correctIndex: 0 },
  { id: "einstein_gerado26_008", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Gestante, 38 anos de idade, 41 semanas e 2 dias, colo desfavorável ao toque (Bishop 3), sem intercorrências na gestação. Qual é a conduta mais apropriada?", options: ["Indução do trabalho de parto com método de preparo cervical.", "Conduta expectante indefinida sem qualquer intervenção.", "Cesariana eletiva imediata pela idade gestacional avançada.", "Amniotomia isolada sem preparo cervical prévio."], correctIndex: 0 },
  { id: "einstein_gerado26_009", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher, 40 anos de idade, apresenta massa anexial complexa de 8 cm ao ultrassom, com componente sólido e vascularização central ao Doppler, CA-125 elevado. Qual é a conduta mais apropriada?", options: ["Encaminhamento para avaliação oncológica e cirurgia estadiadora.", "Punção aspirativa transvaginal como conduta inicial.", "Observação com novo ultrassom em 1 ano.", "Anticoncepcional hormonal combinado isolado."], correctIndex: 0 },
  { id: "einstein_gerado26_010", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Puérpera, 6 horas após parto vaginal, apresenta sangramento importante persistente apesar de útero contraído à palpação. Ao exame especular, identifica-se laceração ativa em parede vaginal lateral. Qual é a conduta?", options: ["Sutura hemostática da laceração.", "Histerectomia imediata sem inspeção do canal de parto.", "Apenas massagem uterina, sem inspecionar o canal vaginal.", "Curetagem uterina como primeira conduta."], correctIndex: 0 },
  { id: "einstein_gerado26_011", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Gestante, 29 anos de idade, com miomatose uterina conhecida, apresenta dor abdominal focal intensa sobre um dos nódulos durante o segundo trimestre, sem sangramento vaginal, com exame obstétrico e cardiotocografia normais. Qual é a hipótese diagnóstica mais provável e a conduta?", options: ["Degeneração vermelha do mioma; analgesia e conduta conservadora.", "Descolamento de placenta; interrupção imediata da gestação.", "Trabalho de parto prematuro; tocólise agressiva imediata.", "Torção anexial; laparoscopia de urgência."], correctIndex: 0 },
  { id: "einstein_gerado26_012", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher, 35 anos de idade, refere ciclos menstruais regulares porém com fluxo intenso e cólicas há 8 meses, iniciados após inserção de dispositivo intrauterino de cobre. Ultrassom sem alterações estruturais. Qual é a conduta inicial mais apropriada?", options: ["Anti-inflamatório não esteroidal no período menstrual e reavaliação; considerar troca do método se persistir.", "Remoção imediata do DIU independente de tentativa de manejo clínico.", "Histerectomia como primeira conduta.", "Antibioticoterapia empírica sem evidência de infecção."], correctIndex: 0 },
  { id: "einstein_gerado26_013", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Gestante, 22 anos de idade, 28 semanas, é diagnosticada com toxoplasmose aguda confirmada por avidez de IgG baixa. Amniocentese com PCR positivo para Toxoplasma gondii no líquido amniótico. Qual é o tratamento indicado a partir desse ponto?", options: ["Esquema tríplice com pirimetamina, sulfadiazina e ácido folínico.", "Espiramicina isolada mantida até o parto, sem mudança de esquema.", "Suspensão de qualquer tratamento, pois a infecção fetal já ocorreu.", "Interrupção da gestação como única conduta apropriada."], correctIndex: 0 },
  { id: "einstein_gerado26_014", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher, 50 anos de idade, apresenta secura vaginal, dispareunia e urgência miccional, na pós-menopausa, sem sangramento ou espessamento endometrial. Qual é o tratamento local de primeira linha para os sintomas genitourinários da menopausa?", options: ["Estrogênio tópico vaginal em baixa dose.", "Terapia hormonal sistêmica em altas doses como única opção.", "Antibiótico profilático contínuo.", "Cirurgia reconstrutiva vaginal como primeira conduta."], correctIndex: 0 },
  { id: "einstein_gerado26_015", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Gestante, 30 anos de idade, 35 semanas, apresenta pressão arterial de 150/95 mmHg em duas aferições, sem proteinúria, cefaleia ou outros sintomas, com exames laboratoriais normais. Qual é o diagnóstico mais provável e a conduta?", options: ["Hipertensão gestacional; monitorização materno-fetal seriada e considerar anti-hipertensivo conforme níveis.", "Pré-eclâmpsia grave; sulfato de magnésio imediato.", "Hipertensão arterial crônica; anti-hipertensivo em altas doses desde já.", "Eclâmpsia iminente; interrupção imediata da gestação."], correctIndex: 0 },
  { id: "einstein_gerado26_016", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente, 7 meses de idade, apresenta febre alta isolada há 3 dias, sem foco identificável ao exame físico, seguida de exantema maculopapular que surge após a defervescência. Qual é o diagnóstico mais provável?", options: ["Exantema súbito (roséola infantil).", "Sarampo.", "Escarlatina.", "Dengue clássica."], correctIndex: 0 },
  { id: "einstein_gerado26_017", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Criança, 5 anos de idade, apresenta dor abdominal periumbilical recorrente há meses, sem sinais de alarme (sem perda de peso, sem sangramento, sem despertar noturno), com exame físico e crescimento normais. Qual é a conduta mais apropriada?", options: ["Investigação mínima e reasseguramento, considerando dor abdominal funcional.", "Colonoscopia diagnóstica imediata em todos os casos.", "Tomografia de abdome como primeira investigação.", "Antiparasitário empírico sem investigação adicional."], correctIndex: 0 },
  { id: "einstein_gerado26_018", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido a termo, com peso adequado para idade gestacional, apresenta tremores finos e irritabilidade nas primeiras 24 horas de vida. Mãe com diabetes gestacional mal controlada. Glicemia capilar do recém-nascido de 32 mg/dL. Qual é a conduta inicial?", options: ["Estímulo à amamentação precoce e frequente, com glicose intravenosa se sintomático e refratário.", "Insulina para o recém-nascido imediatamente.", "Jejum absoluto por 24 horas para repouso metabólico.", "Alta hospitalar sem monitorização glicêmica adicional."], correctIndex: 0 },
  { id: "einstein_gerado26_019", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Criança, 2 anos de idade, apresenta estridor inspiratório de início súbito durante refeição, com tosse súbita e engasgo presenciado pelos pais, mantendo-se capaz de tossir e chorar. Qual é a conduta imediata?", options: ["Estimular a tosse espontânea e observar, sem manobras de desobstrução enquanto a tosse for efetiva.", "Manobra de Heimlich imediata, independente da tosse ser efetiva.", "Compressões torácicas imediatas, independente da idade.", "Varredura digital às cegas na cavidade oral."], correctIndex: 0 },
  { id: "einstein_gerado26_020", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente, 3 meses de idade, apresenta tosse paroxística intensa seguida de guincho inspiratório e episódio de apneia presenciado pelos pais, sem febre. Vacinação incompleta para a idade. Qual é o diagnóstico mais provável e a principal preocupação nessa faixa etária?", options: ["Coqueluche; risco de apneia e complicações graves em lactentes jovens.", "Bronquiolite viral; sem risco de apneia associado.", "Asma do lactente; sem relação com vacinação incompleta.", "Refluxo gastroesofágico; sem relação com tosse paroxística."], correctIndex: 0 },
  { id: "einstein_gerado26_021", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Criança, 4 anos de idade, apresenta manchas café com leite múltiplas (mais de 6, maiores que 5 mm), sardas axilares e nódulos subcutâneos palpáveis. Qual é o diagnóstico mais provável?", options: ["Neurofibromatose tipo 1.", "Esclerose tuberosa.", "Síndrome de McCune-Albright.", "Síndrome de Sturge-Weber."], correctIndex: 0 },
  { id: "einstein_gerado26_022", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido termo, 5 dias de vida, apresenta secreção purulenta ocular bilateral abundante, com edema palpebral importante. Mãe sem pré-natal adequado. Qual é o agente mais provável e a gravidade associada?", options: ["Neisseria gonorrhoeae; risco de perfuração corneana se não tratado prontamente.", "Staphylococcus epidermidis; quadro habitualmente leve e autolimitado.", "Vírus herpes simples; tratamento apenas com colírio lubrificante.", "Chlamydia trachomatis; sem risco de complicação ocular grave."], correctIndex: 0 },
  { id: "einstein_gerado26_023", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Escolar, 7 anos de idade, apresenta baixa estatura importante (abaixo do percentil 3), velocidade de crescimento reduzida e idade óssea atrasada em relação à idade cronológica, sem outras alterações ao exame físico. Qual é a investigação inicial mais apropriada?", options: ["Dosagem de hormônio do crescimento, IGF-1 e avaliação da função tireoidiana.", "Cariótipo isolado, sem avaliação hormonal.", "Ressonância magnética de crânio como primeiro exame, sem avaliação hormonal prévia.", "Apenas acompanhamento nutricional, sem investigação hormonal."], correctIndex: 0 },
  { id: "einstein_gerado26_024", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente, 6 meses de idade, apresenta hepatoesplenomegalia, atraso do desenvolvimento neuropsicomotor e mancha vermelho-cereja na região macular ao exame de fundo de olho. Qual é a hipótese diagnóstica mais provável?", options: ["Doença de Tay-Sachs.", "Síndrome de Down.", "Hipotireoidismo congênito.", "Fenilcetonúria."], correctIndex: 0 },
  { id: "einstein_gerado26_025", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Criança, 3 anos de idade, apresenta claudicação súbita e recusa de apoiar o membro inferior direito, sem trauma referido, febre baixa e proteína C reativa discretamente elevada. Radiografia sem alterações. Qual é a hipótese diagnóstica mais provável e a conduta?", options: ["Sinovite transitória de quadril; repouso e anti-inflamatório com reavaliação.", "Artrite séptica; punção articular obrigatória em todos os casos, independente da clínica.", "Osteossarcoma; biópsia óssea imediata.", "Doença de Legg-Calvé-Perthes; cirurgia imediata."], correctIndex: 0 },
  { id: "einstein_gerado26_026", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido pré-termo tardio, 36 semanas, apresenta dificuldade de sucção e hipoatividade. Triagem neonatal (teste do pezinho) mostra TSH elevado. Qual é a importância do início precoce do tratamento?", options: ["Prevenir dano neurológico irreversível associado ao hipotireoidismo congênito.", "Prevenir apenas baixa estatura, sem risco neurológico.", "Tratamento pode ser postergado até os 2 anos sem prejuízo.", "Relevante apenas para prevenir obesidade futura."], correctIndex: 0 },
  { id: "einstein_gerado26_027", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Escolar, 10 anos de idade, apresenta poliúria, polidipsia e perda de peso há 3 semanas, com glicemia capilar de 420 mg/dL e cetonúria positiva, porém sem desidratação importante nem alteração do nível de consciência. Qual é a conduta inicial mais apropriada?", options: ["Hidratação e insulinoterapia conforme protocolo de cetoacidose diabética, com monitorização de potássio.", "Insulina de ação prolongada isolada, sem hidratação venosa.", "Alta com insulina subcutânea e retorno ambulatorial em 1 semana.", "Bicarbonato de sódio como primeira medida terapêutica."], correctIndex: 0 },
  { id: "einstein_gerado26_028", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente, 8 meses de idade, apresenta tosse, coriza e sibilância, com necessidade de oxigênio suplementar por saturação de 90%, ainda mamando bem. Qual é a conduta quanto ao uso de broncodilatador e corticoide na bronquiolite viral aguda?", options: ["Não há indicação rotineira de broncodilatador nem corticoide; o tratamento é de suporte.", "Broncodilatador e corticoide sistêmico devem ser sempre associados.", "Corticoide sistêmico isolado é obrigatório em todo caso de bronquiolite.", "Antibiótico empírico deve ser iniciado de rotina."], correctIndex: 0 },
  { id: "einstein_gerado26_029", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Criança, 6 anos de idade, apresenta enurese noturna isolada, sem sintomas diurnos, sem alterações ao exame físico e urina rotina normal. Qual é a conduta inicial mais apropriada?", options: ["Orientação comportamental e reasseguramento aos pais, considerando a idade ainda dentro da normalidade.", "Início imediato de desmopressina sem qualquer orientação comportamental prévia.", "Investigação urológica invasiva imediata.", "Restrição hídrica extrema durante todo o dia."], correctIndex: 0 },
  { id: "einstein_gerado26_030", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido apresenta ausência de eliminação de mecônio nas primeiras 48 horas de vida, distensão abdominal progressiva e vômitos. Biópsia retal confirma ausência de células ganglionares. Qual é o diagnóstico e o tratamento definitivo?", options: ["Doença de Hirschsprung; ressecção cirúrgica do segmento agangliônico.", "Íleo meconial; apenas enema terapêutico, sem cirurgia em nenhum caso.", "Atresia anal; dilatações seriadas isoladas.", "Estenose hipertrófica de piloro; piloromiotomia."], correctIndex: 0 },
  { id: "einstein_gerado26_031", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Adolescente, 14 anos de idade, sexo feminino, apresenta ausência de menarca, estatura baixa, pescoço alado e implantação baixa de cabelos. Cariótipo confirma 45,X0. Qual é a principal complicação cardiovascular a ser rastreada?", options: ["Coarctação de aorta.", "Estenose mitral reumática.", "Miocardiopatia dilatada isolada.", "Pericardite constritiva."], correctIndex: 0 },
  { id: "einstein_gerado26_032", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente, 11 meses de idade, apresenta palidez cutânea importante, irritabilidade e dieta baseada quase exclusivamente em leite de vaca, sem introdução adequada de alimentos ricos em ferro. Hemograma confirma anemia microcítica hipocrômica. Qual é a conduta terapêutica?", options: ["Suplementação de ferro oral e orientação de diversificação alimentar.", "Transfusão sanguínea imediata independente do nível de hemoglobina.", "Suspensão total do leite de vaca sem qualquer suplementação.", "Vitamina B12 isolada, sem suplementação de ferro."], correctIndex: 0 },
  { id: "einstein_gerado26_033", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido, 2 dias de vida, apresenta icterícia visível já nas primeiras 24 horas de vida, com bilirrubina total de 16 mg/dL de predomínio indireto. Grupo sanguíneo materno O negativo, do recém-nascido A positivo, Coombs direto positivo. Qual é o diagnóstico mais provável?", options: ["Doença hemolítica perinatal por incompatibilidade ABO/Rh.", "Icterícia fisiológica do recém-nascido.", "Icterícia do leite materno.", "Atresia de vias biliares."], correctIndex: 0 },
  { id: "einstein_gerado26_034", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Criança, 12 anos de idade, apresenta ganho de peso importante, estrias violáceas em abdome e face pletórica. História de uso prolongado de corticoide inalatório em altas doses para asma grave. Qual é a hipótese diagnóstica mais provável?", options: ["Síndrome de Cushing exógena por uso crônico de corticoide.", "Obesidade exógena simples, sem relação com a medicação.", "Síndrome metabólica isolada, sem relação com o corticoide.", "Hipotireoidismo primário isolado."], correctIndex: 0 },
  { id: "einstein_gerado26_035", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 50 anos de idade, apresenta massa abdominal pulsátil e indolor em região periumbilical, achado incidental em exame de rotina. Ultrassom confirma aneurisma de aorta abdominal infrarrenal de 5,8 cm, assintomático. Qual é a conduta mais adequada?", options: ["Correção cirúrgica eletiva (aberta ou endovascular), dado o diâmetro acima do limiar de intervenção.", "Acompanhamento seriado sem intervenção, independente do diâmetro.", "Anticoagulação plena isolada, sem cirurgia.", "Embolização isolada sem exclusão do saco aneurismático."], correctIndex: 0 },
  { id: "einstein_gerado26_036", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 45 anos de idade, apresenta hérnia inguinal indireta redutível, sintomática, sem sinais de encarceramento. Qual é a conduta mais apropriada?", options: ["Correção cirúrgica eletiva (herniorrafia).", "Uso de cinta compressiva como tratamento definitivo.", "Observação isolada, sem qualquer intervenção, mesmo sintomática.", "Antibioticoterapia profilática isolada, sem cirurgia."], correctIndex: 0 },
  { id: "einstein_gerado26_037", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Mulher, 38 anos de idade, no 3º dia de pós-operatório de colecistectomia videolaparoscópica, apresenta febre, dor abdominal e saída de líquido biliar pelo dreno. Qual é a hipótese diagnóstica mais provável e a conduta inicial?", options: ["Fístula/lesão de via biliar; investigação por colangiografia ou CPRE e drenagem adequada.", "Infecção de sítio cirúrgico superficial; apenas curativo local, sem outra investigação.", "Pancreatite aguda leve; apenas jejum, sem investigação da via biliar.", "Íleo pós-operatório simples; apenas observação, sem investigação adicional."], correctIndex: 0 },
  { id: "einstein_gerado26_038", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 60 anos de idade, tabagista, apresenta massa palpável em região cervical lateral, indolor, de crescimento progressivo há 3 meses, sem outros sintomas. Qual é a conduta diagnóstica inicial mais apropriada?", options: ["Punção aspirativa por agulha fina da lesão.", "Biópsia excisional como primeira conduta, sem punção prévia.", "Antibioticoterapia empírica prolongada, sem investigação.", "Observação clínica por 6 meses antes de qualquer investigação."], correctIndex: 0 },
  { id: "einstein_gerado26_039", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 55 anos de idade, apresenta massa em região inguinal com dor à palpação, sem sinais de obstrução intestinal, redutível ao exame. Qual é a conduta considerando o risco de progressão para encarceramento?", options: ["Correção cirúrgica eletiva em tempo apropriado, mesmo sem sinais de encarceramento atual.", "Observação isolada por tempo indefinido, mesmo sintomática.", "Apenas analgesia, sem indicação cirúrgica em qualquer momento.", "Antibioticoterapia profilática isolada."], correctIndex: 0 },
  { id: "einstein_gerado26_040", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Mulher, 65 anos de idade, apresenta massa palpável em mama direita, endurecida, aderida a planos profundos, com retração cutânea (\"casca de laranja\") ao exame físico. Qual é a conduta diagnóstica inicial mais apropriada?", options: ["Mamografia e biópsia da lesão.", "Mastectomia imediata sem confirmação histológica.", "Apenas seguimento clínico em 6 meses.", "Quimioterapia empírica sem biópsia prévia."], correctIndex: 0 },
  { id: "einstein_gerado26_041", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 48 anos de idade, apresenta dor anal intensa à evacuação, com sangramento vivo em papel higiênico, e fissura linear visível na linha média posterior ao exame proctológico. Qual é o tratamento inicial mais apropriado?", options: ["Medidas conservadoras: dieta rica em fibras, banho de assento e pomada relaxante do esfíncter.", "Esfincterotomia cirúrgica como primeira conduta, sem tentativa clínica.", "Hemorroidectomia, independente do diagnóstico de fissura.", "Antibioticoterapia sistêmica isolada."], correctIndex: 0 },
  { id: "einstein_gerado26_042", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 70 anos de idade, apresenta dor abdominal difusa, distensão e parada de eliminação de fezes e gases há 3 dias, com radiografia de abdome mostrando distensão importante de cólon e reto sem ponto de obstrução mecânica evidente (Síndrome de Ogilvie). Qual é a conduta inicial?", options: ["Correção de distúrbios metabólicos e considerar neostigmina se refratário, antes de intervenção cirúrgica.", "Colectomia total de urgência em todos os casos.", "Apenas jejum prolongado, sem qualquer medicação específica.", "Antibioticoterapia isolada, sem descompressão do cólon."], correctIndex: 0 },
  { id: "einstein_gerado26_043", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Mulher, 42 anos de idade, apresenta dor em fossa ilíaca direita, massa palpável e febre baixa persistente após tratamento de apendicite complicada há 10 dias. Tomografia mostra coleção líquida circunscrita de 6 cm adjacente ao ceco. Qual é a conduta mais apropriada?", options: ["Drenagem percutânea guiada por imagem e antibioticoterapia.", "Reoperação imediata com laparotomia ampla como primeira escolha.", "Apenas antibiótico oral, sem drenagem.", "Observação sem qualquer intervenção adicional."], correctIndex: 0 },
  { id: "einstein_gerado26_044", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 35 anos de idade, vítima de ferimento por arma de fogo em abdome, hemodinamicamente instável apesar de reposição volêmica inicial. Qual é a conduta mais apropriada?", options: ["Laparotomia exploradora de urgência.", "Tomografia computadorizada antes de qualquer decisão cirúrgica.", "Observação em UTI com reavaliação em 6 horas.", "FAST isolado sem indicação cirúrgica, independente do resultado."], correctIndex: 0 },
  { id: "einstein_gerado26_045", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 58 anos de idade, apresenta disfagia progressiva, perda de peso importante e odinofagia. Endoscopia digestiva alta com biópsia confirma carcinoma epidermoide de esôfago médio. Qual é a próxima etapa antes de definir o tratamento?", options: ["Estadiamento com tomografia, ultrassonografia endoscópica e avaliação de metástases.", "Esofagectomia imediata sem qualquer estadiamento.", "Quimioterapia isolada sem avaliação cirúrgica.", "Apenas suporte nutricional, sem tratamento oncológico específico."], correctIndex: 0 },
  { id: "einstein_gerado26_046", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Mulher, 30 anos de idade, apresenta abaulamento doloroso em região perianal, com hiperemia e flutuação à palpação, febre baixa. Qual é o tratamento definitivo?", options: ["Drenagem cirúrgica do abscesso.", "Antibioticoterapia isolada, sem drenagem.", "Apenas banho de assento, sem qualquer outra conduta.", "Observação clínica, aguardando drenagem espontânea."], correctIndex: 0 },
  { id: "einstein_gerado26_047", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 62 anos de idade, apresenta alteração do hábito intestinal, sangue oculto nas fezes positivo e anemia ferropriva. Colonoscopia identifica lesão vegetante estenosante em cólon sigmoide, biópsia confirma adenocarcinoma. Qual é a próxima etapa antes da cirurgia?", options: ["Estadiamento com tomografia de tórax, abdome e pelve, e dosagem de CEA.", "Colectomia imediata sem qualquer estadiamento.", "Quimioterapia isolada sem avaliação cirúrgica prévia.", "Apenas observação clínica sem qualquer conduta adicional."], correctIndex: 0 },
  { id: "einstein_gerado26_048", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Mulher, 28 anos de idade, apresenta nódulo tireoidiano palpável de crescimento rápido, com rouquidão associada e linfonodo cervical palpável ipsilateral. Punção aspirativa confirma carcinoma papilífero de tireoide. Qual é a conduta cirúrgica mais apropriada?", options: ["Tireoidectomia total com esvaziamento linfonodal conforme extensão.", "Apenas nodulectomia isolada, sem tireoidectomia.", "Observação clínica sem cirurgia, mesmo com confirmação histológica.", "Radioterapia externa isolada, sem cirurgia."], correctIndex: 0 },
  { id: "einstein_gerado26_049", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 66 anos de idade, apresenta dor abdominal pós-prandial recorrente ('angina intestinal'), perda de peso e medo de se alimentar. Angiotomografia mostra estenose significativa de tronco celíaco e artéria mesentérica superior. Qual é a hipótese diagnóstica mais provável?", options: ["Isquemia mesentérica crônica.", "Úlcera péptica não complicada.", "Pancreatite crônica calcificante isolada.", "Síndrome do intestino irritável."], correctIndex: 0 },
  { id: "einstein_gerado26_050", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Mulher, 45 anos de idade, apresenta dor abdominal em quadrante superior direito recorrente, associada a náuseas, com ultrassom mostrando múltiplos cálculos vesiculares sem sinais de complicação aguda no momento do exame. Qual é a conduta mais apropriada diante da colelitíase sintomática?", options: ["Colecistectomia videolaparoscópica eletiva.", "Ácido ursodesoxicólico isolado como tratamento definitivo.", "Observação isolada, mesmo sintomática.", "Litotripsia extracorpórea como primeira escolha."], correctIndex: 0 },
  { id: "einstein_gerado26_051", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 40 anos de idade, apresenta dor abdominal intensa em faixa irradiada para o dorso, náuseas e vômitos após ingestão alcoólica importante. Lipase 6 vezes o valor de referência, sem sinais de colelitíase ao ultrassom. Qual é a conduta inicial?", options: ["Hidratação venosa vigorosa, analgesia e jejum inicial conforme tolerância.", "Antibioticoterapia profilática de rotina em todos os casos leves.", "Cirurgia pancreática imediata.", "CPRE de urgência independente de obstrução biliar."], correctIndex: 0 },
  { id: "einstein_gerado26_052", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Mulher, 52 anos de idade, apresenta abaulamento redutível na linha média, acima da cicatriz umbilical, doloroso à palpação, com história de cirurgia abdominal prévia por via mediana. Qual é o diagnóstico e a conduta?", options: ["Hérnia incisional; correção cirúrgica eletiva, geralmente com tela.", "Diástase de retos abdominais; apenas fisioterapia, sem cirurgia.", "Lipoma subcutâneo; observação isolada.", "Endometriose de parede abdominal; apenas hormonioterapia."], correctIndex: 0 },
  { id: "einstein_gerado26_053", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 33 anos de idade, vítima de acidente motociclístico, apresenta fratura de bacia com instabilidade hemodinâmica refratária a reposição volêmica inicial. Qual é a conduta mais apropriada para controle do sangramento pélvico?", options: ["Estabilização pélvica externa e considerar embolização angiográfica ou packing pélvico.", "Observação isolada sem qualquer estabilização.", "Laparotomia exploradora como única conduta, sem estabilizar a pelve.", "Alta para transferência ambulatorial em outro serviço."], correctIndex: 0 },
  { id: "einstein_gerado26_054", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Mulher, 47 anos de idade, apresenta dor lombar recorrente e cálculos renais bilaterais de repetição, com hipercalciúria e nefrocalcinose. Cálcio e PTH séricos elevados. Qual é a conduta definitiva mais apropriada?", options: ["Paratireoidectomia.", "Restrição hídrica isolada.", "Nefrectomia bilateral.", "Apenas analgesia para as crises de cólica, sem tratar a causa."], correctIndex: 0 },
  { id: "einstein_gerado26_055", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 25 anos de idade, apresenta ferimento superficial em couro cabeludo por acidente doméstico com objeto enferrujado, esquema vacinal antitetânico incompleto e desconhecido. Qual é a conduta apropriada quanto à profilaxia do tétano?", options: ["Vacina antitetânica e imunoglobulina antitetânica, conforme tipo de ferimento e histórico vacinal.", "Nenhuma profilaxia é necessária para ferimentos superficiais.", "Apenas antibiótico oral, sem qualquer profilaxia vacinal.", "Soro antitetânico isolado, sem vacina."], correctIndex: 0 },
  { id: "einstein_gerado26_056", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 58 anos de idade, apresenta massa pulsátil dolorosa em abdome com hipotensão súbita, história de aneurisma de aorta conhecido de 6 cm em acompanhamento ambulatorial. Qual é a hipótese diagnóstica e a conduta?", options: ["Rotura de aneurisma de aorta abdominal; cirurgia de urgência.", "Cólica renal; apenas analgesia, sem investigação de urgência.", "Pancreatite aguda; apenas hidratação, sem avaliação vascular.", "Diverticulite aguda; antibioticoterapia isolada."], correctIndex: 0 },
  { id: "einstein_gerado26_057", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Homem, 55 anos de idade, tabagista, hipertenso, comparece à unidade básica de saúde para consulta de rotina, sem queixas agudas. Qual é a conduta de rastreamento de câncer colorretal mais apropriada para essa faixa etária e perfil de risco padrão?", options: ["Pesquisa de sangue oculto nas fezes ou colonoscopia conforme protocolo de rastreamento, a partir dos 45-50 anos.", "Colonoscopia obrigatória anual a partir dos 30 anos, independente do risco.", "Nenhum rastreamento é indicado antes dos 70 anos.", "Apenas exame de toque retal isolado, sem outros métodos."], correctIndex: 0 },
  { id: "einstein_gerado26_058", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Mulher, 45 anos de idade, comparece à unidade de saúde da família para consulta de rotina sem queixas. Qual é a conduta de rastreamento de câncer de mama mais apropriada, conforme diretrizes nacionais para risco habitual?", options: ["Mamografia de rastreamento a partir dos 50 anos, bienal, conforme diretriz vigente para risco habitual.", "Ressonância magnética de mama anual desde os 40 anos, independente do risco.", "Nenhum rastreamento antes dos 60 anos.", "Ultrassonografia mamária isolada, sem mamografia."], correctIndex: 0 },
  { id: "einstein_gerado26_059", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Equipe de saúde da família realiza visita domiciliar a idoso acamado, com apoio de cuidador familiar sobrecarregado. Qual é a abordagem mais apropriada da equipe nesse contexto?", options: ["Avaliação multidimensional do idoso e suporte ao cuidador, incluindo orientação sobre rede de apoio.", "Encaminhamento imediato para institucionalização, sem avaliação prévia.", "Foco exclusivo nas queixas físicas do idoso, sem avaliar o cuidador.", "Alta do acompanhamento domiciliar por não ser atribuição da atenção básica."], correctIndex: 0 },
  { id: "einstein_gerado26_060", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Paciente de 60 anos, tabagista de longa data (40 anos-maço), assintomático, procura a unidade básica para check-up. Qual é a conduta de rastreamento de câncer de pulmão mais apropriada conforme critérios de risco?", options: ["Tomografia de tórax de baixa dose anual, conforme critérios de alto risco (idade e carga tabágica).", "Radiografia de tórax anual isolada, com sensibilidade equivalente à tomografia.", "Nenhum rastreamento é recomendado para câncer de pulmão em qualquer perfil.", "Broncoscopia de rotina como método de rastreamento."], correctIndex: 0 },
  { id: "einstein_gerado26_061", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Paciente comparece à unidade básica de saúde solicitando atestado médico retroativo para justificar falta ao trabalho por sintomas já resolvidos, sem ter sido atendido no dia da falta. Qual é a conduta ética apropriada?", options: ["Recusar a emissão de atestado retroativo sem exame e avaliação apropriados no momento do sintoma.", "Emitir o atestado normalmente, por se tratar de solicitação do paciente.", "Emitir o atestado apenas se o paciente insistir repetidamente.", "Encaminhar para outro profissional emitir sem qualquer critério adicional."], correctIndex: 0 },
  { id: "einstein_gerado26_062", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Equipe de atenção básica organiza classificação de risco cardiovascular em pacientes hipertensos e diabéticos da área adstrita, priorizando consultas e monitorização mais frequentes aos de maior risco. Qual conceito da Atenção Primária essa prática representa?", options: ["Estratificação de risco para organização do cuidado longitudinal.", "Hierarquização rígida sem relação com risco individual.", "Atenção terciária aplicada à atenção básica.", "Universalização do atendimento sem qualquer priorização."], correctIndex: 0 },
  { id: "einstein_gerado26_063", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Paciente de 50 anos, obeso, sedentário, com glicemia de jejum alterada em dois exames (110 mg/dL), sem diagnóstico de diabetes. Qual é a conduta mais apropriada na atenção básica?", options: ["Orientação de mudança de estilo de vida (dieta e atividade física) e reavaliação periódica.", "Iniciar metformina em altas doses imediatamente, independente de mudança de hábitos.", "Insulina basal desde o diagnóstico de pré-diabetes.", "Nenhuma conduta, pois glicemia de jejum alterada não requer acompanhamento."], correctIndex: 0 },
  { id: "einstein_gerado26_064", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Adolescente de 16 anos comparece à unidade de saúde sozinho, solicitando orientação sobre método contraceptivo, sem desejo de que os pais sejam informados. Qual é a conduta apropriada quanto ao sigilo?", options: ["Atender o adolescente e manter o sigilo, respeitando sua autonomia e capacidade de compreensão, conforme diretrizes de atenção à saúde do adolescente.", "Recusar atendimento sem presença dos responsáveis.", "Informar os pais obrigatoriamente antes de qualquer orientação.", "Encaminhar diretamente para o Conselho Tutelar, sem qualquer atendimento clínico."], correctIndex: 0 },
  { id: "einstein_gerado26_065", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Município apresenta aumento expressivo de casos de dengue em bairro específico durante período chuvoso. Qual é a principal medida de vigilância e controle a ser priorizada pela equipe de saúde?", options: ["Eliminação de criadouros do Aedes aegypti e notificação compulsória dos casos suspeitos.", "Vacinação de toda a população do bairro como única medida.", "Isolamento domiciliar obrigatório de todos os moradores.", "Fechamento total das unidades de saúde da região."], correctIndex: 0 },
  { id: "einstein_gerado26_066", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Gestor municipal de saúde organiza o fluxo de atendimento entre unidades básicas, especialidades e hospitais em níveis de complexidade crescente, com referência e contrarreferência. Qual princípio organizativo do SUS orienta essa organização?", options: ["Hierarquização e regionalização.", "Universalidade isolada, sem relação com organização de fluxo.", "Equidade isolada, sem relação com estrutura de rede.", "Integralidade isolada, sem relação com níveis de complexidade."], correctIndex: 0 },
  { id: "einstein_gerado26_067", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Estudo epidemiológico avalia a proporção de indivíduos com determinada doença em uma população em um momento específico no tempo. Qual medida epidemiológica está sendo calculada?", options: ["Prevalência.", "Incidência acumulada.", "Densidade de incidência.", "Risco relativo."], correctIndex: 0 },
  { id: "einstein_gerado26_068", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Pesquisador avalia um novo teste diagnóstico e calcula a proporção de resultados positivos entre os indivíduos verdadeiramente doentes. Qual propriedade do teste está sendo calculada?", options: ["Sensibilidade.", "Especificidade.", "Valor preditivo positivo.", "Valor preditivo negativo."], correctIndex: 0 },
  { id: "einstein_gerado26_069", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Equipe de vigilância epidemiológica identifica agrupamento de casos de doença diarreica aguda em creche, todos com início de sintomas em período de tempo próximo e relacionado a uma mesma refeição. Qual conceito epidemiológico melhor descreve esse padrão de ocorrência?", options: ["Surto por fonte comum.", "Endemia.", "Pandemia.", "Epidemia de propagação (pessoa a pessoa) sem fonte comum."], correctIndex: 0 },
  { id: "einstein_gerado26_070", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Órgão de vigilância sanitária realiza inspeção em hospital, avaliando processos de esterilização de materiais e descarte de resíduos, prevenindo eventos adversos e infecções relacionadas à assistência. Qual campo da vigilância em saúde essa atividade representa?", options: ["Vigilância sanitária.", "Vigilância epidemiológica.", "Vigilância nutricional.", "Vigilância da saúde do trabalhador exclusivamente."], correctIndex: 0 },
  { id: "einstein_gerado26_071", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Gestor de saúde pública analisa dados que mostram maior mortalidade por doenças cardiovasculares em populações de menor renda, mesmo após ajuste para fatores de risco biológicos clássicos. Qual conceito melhor explica esse achado?", options: ["Iniquidades em saúde relacionadas aos determinantes sociais.", "Causalidade estritamente genética, sem influência ambiental.", "Erro amostral inevitável em qualquer estudo epidemiológico.", "Fenômeno aleatório sem relação causal identificável."], correctIndex: 0 },
  { id: "einstein_gerado26_072", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Equipe de saúde mental da atenção básica discute caso complexo junto a especialista do CAPS, sem necessariamente encaminhar o paciente, mantendo vínculo com a equipe de referência. Qual estratégia organizativa da Atenção Primária essa prática representa?", options: ["Apoio matricial (matriciamento) em saúde mental.", "Referência hospitalar direta sem contrarreferência.", "Hierarquização rígida sem compartilhamento de caso.", "Encaminhamento definitivo sem corresponsabilização."], correctIndex: 0 },
  { id: "einstein_gerado26_073", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Medicina de Emergência", text: "Homem, 45 anos de idade, é trazido ao pronto-socorro após acidente automobilístico, com via aérea pérvia, mas com respiração ruidosa e murmúrio vesicular diminuído à direita, PA 85x50 mmHg. Qual é a sequência de avaliação e conduta inicial segundo o protocolo de atendimento ao trauma?", options: ["Avaliação primária ABCDE, com atenção ao tórax e reposição volêmica conforme achados.", "Solicitar tomografia de corpo inteiro antes de qualquer intervenção.", "Avaliação neurológica isolada antes de avaliar via aérea e respiração.", "Alta após analgesia, sem avaliação sistematizada."], correctIndex: 0 },
  { id: "einstein_gerado26_074", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Medicina de Emergência", text: "Paciente é atendido em parada cardiorrespiratória, com ritmo de fibrilação ventricular confirmado no monitor. Qual é a conduta imediata mais apropriada, após reconhecimento da parada e início de compressões torácicas de alta qualidade?", options: ["Desfibrilação precoce assim que disponível.", "Aguardar acesso venoso central antes de qualquer choque.", "Administrar apenas adrenalina, sem desfibrilação, independente do ritmo.", "Intubação orotraqueal antes de qualquer outra medida, mesmo atrasando o choque."], correctIndex: 0 },
  { id: "einstein_gerado26_075", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Medicina de Emergência", text: "Paciente chega ao pronto-socorro com rebaixamento do nível de consciência, pupilas puntiformes e frequência respiratória de 6 irpm, com história de uso de opioide. Qual é a conduta imediata mais apropriada?", options: ["Suporte ventilatório e administração de naloxona.", "Flumazenil isolado, independente da suspeita de opioide.", "Apenas observação clínica sem qualquer antídoto.", "Lavagem gástrica isolada, sem suporte ventilatório."], correctIndex: 0 },
  { id: "einstein_gerado26_076", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Medicina de Emergência", text: "Paciente apresenta reação anafilática após picada de inseto, com edema de face, urticária difusa, dispneia e hipotensão. Qual é a conduta farmacológica imediata mais importante?", options: ["Adrenalina intramuscular imediata.", "Anti-histamínico isolado como primeira medida.", "Corticoide isolado como primeira medida.", "Broncodilatador isolado, sem adrenalina."], correctIndex: 0 },
  { id: "einstein_gerado26_077", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Medicina de Emergência", text: "Paciente é atendido em unidade de emergência com múltiplas vítimas simultâneas de um acidente com ônibus. Qual é o princípio fundamental que deve orientar a triagem inicial nesse cenário de múltiplas vítimas?", options: ["Priorizar o atendimento conforme gravidade e chance de sobrevida, não por ordem de chegada.", "Atender estritamente por ordem de chegada, independente da gravidade.", "Atender primeiro os pacientes com queixas mais verbalizadas.", "Transferir todos imediatamente sem qualquer triagem no local."], correctIndex: 0 },
  { id: "einstein_gerado26_078", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Clínica Médica", text: "Homem, 55 anos de idade, apresenta dor torácica típica ao esforço, aliviada com repouso, com ECG de repouso normal. Qual é o exame inicial mais apropriado para investigação de doença arterial coronariana estável?", options: ["Teste ergométrico ou exame de imagem funcional/anatômico conforme probabilidade pré-teste.", "Cateterismo cardíaco imediato em todos os casos, independente da probabilidade pré-teste.", "Apenas repetir o ECG de repouso seriadamente.", "Angioplastia empírica sem qualquer exame complementar prévio."], correctIndex: 0 },
  { id: "einstein_gerado26_079", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Clínica Médica", text: "Mulher, 62 anos de idade, apresenta fadiga, palidez e icterícia leve. Hemograma mostra anemia com reticulocitose, LDH elevado, haptoglobina baixa e Coombs direto positivo. Qual é o diagnóstico e o tratamento de primeira linha?", options: ["Anemia hemolítica autoimune; corticoterapia.", "Anemia ferropriva; reposição de ferro oral.", "Anemia megaloblástica; reposição de vitamina B12.", "Talassemia maior; transfusões crônicas isoladas."], correctIndex: 0 },
  { id: "einstein_gerado26_080", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Clínica Médica", text: "Homem, 68 anos de idade, apresenta fadiga progressiva, dispneia aos esforços e edema de membros inferiores, com ecocardiograma mostrando espessamento importante do miocárdio, padrão de infiltração e disfunção diastólica. Eletroforese de proteínas com componente monoclonal. Qual é a hipótese diagnóstica mais provável?", options: ["Amiloidose cardíaca.", "Cardiomiopatia hipertrófica familiar isolada.", "Pericardite constritiva isolada.", "Miocardite viral aguda."], correctIndex: 0 },
  { id: "einstein_gerado26_081", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Clínica Médica", text: "Mulher, 40 anos de idade, apresenta fadiga, xerostomia e xeroftalmia importantes há 2 anos, com biópsia de glândula salivar menor mostrando infiltrado linfocitário. Anti-Ro/SSA e anti-La/SSB positivos. Qual é o diagnóstico mais provável?", options: ["Síndrome de Sjögren.", "Lúpus eritematoso sistêmico isolado.", "Esclerose sistêmica.", "Sarcoidose isolada."], correctIndex: 0 },
  { id: "einstein_gerado26_082", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Clínica Médica", text: "Homem, 50 anos de idade, apresenta poliúria, polidipsia importantes e sódio sérico elevado, com urina muito diluída apesar da hiperosmolalidade sérica. Restrição hídrica não concentra a urina, mas desmopressina melhora a concentração urinária. Qual é o diagnóstico mais provável?", options: ["Diabetes insípido central.", "Diabetes insípido nefrogênico.", "SIADH.", "Polidipsia psicogênica."], correctIndex: 0 },
  { id: "einstein_gerado26_083", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Homem, 32 anos de idade, HIV positivo, contagem de CD4 de 90 células/mm³, apresenta tosse seca progressiva, dispneia aos esforços e febre baixa, com radiografia de tórax mostrando infiltrado intersticial bilateral. Qual é a hipótese diagnóstica mais provável e o tratamento de escolha?", options: ["Pneumonia por Pneumocystis jirovecii; sulfametoxazol-trimetoprima.", "Tuberculose pulmonar; esquema RIPE isolado, sem outra investigação.", "Pneumonia bacteriana comunitária típica; betalactâmico isolado.", "Sarcoma de Kaposi pulmonar; quimioterapia isolada."], correctIndex: 0 },
  { id: "einstein_gerado26_084", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Mulher, 28 anos de idade, apresenta febre, exantema petequial e rigidez de nuca de início agudo, com rebaixamento do nível de consciência. Líquor com pleocitose neutrofílica importante. Qual é a conduta imediata antes mesmo do resultado da cultura?", options: ["Antibioticoterapia empírica imediata, sem aguardar resultado da cultura.", "Aguardar resultado da cultura para iniciar antibiótico.", "Apenas corticoide isolado, sem antibiótico.", "Alta com anti-inflamatório e retorno ambulatorial."], correctIndex: 0 },
  { id: "einstein_gerado26_085", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Homem, 45 anos de idade, retorna de viagem a área endêmica de malária, apresentando febre cíclica, calafrios e sudorese. Gota espessa confirma Plasmodium falciparum. Qual é a conduta terapêutica considerando o risco de complicação grave dessa espécie?", options: ["Tratamento antimalárico imediato, com atenção a sinais de gravidade que indiquem internação.", "Apenas sintomáticos, sem tratamento antimalárico específico.", "Aguardar confirmação por sorologia antes de tratar.", "Antibiótico de amplo espectro isolado, sem antimalárico."], correctIndex: 0 },
  { id: "einstein_gerado26_086", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Homem, 60 anos de idade, apresenta palpitações súbitas, ECG mostrando taquicardia de complexo estreito, regular, com frequência de 180 bpm. Realizada manobra vagal sem sucesso. Qual é a conduta farmacológica de escolha nesse momento, com paciente estável?", options: ["Adenosina intravenosa em bolus.", "Amiodarona isolada como primeira escolha.", "Cardioversão elétrica imediata, independente da estabilidade.", "Digoxina intravenosa como primeira escolha."], correctIndex: 0 },
  { id: "einstein_gerado26_087", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Homem, 65 anos de idade, apresenta dispneia paroxística noturna, ortopneia e edema de membros inferiores, com BNP muito elevado e fração de ejeção preservada ao ecocardiograma. Qual é o diagnóstico mais provável?", options: ["Insuficiência cardíaca com fração de ejeção preservada.", "Insuficiência cardíaca com fração de ejeção reduzida isolada.", "Cor pulmonale agudo isolado.", "Tamponamento cardíaco crônico."], correctIndex: 0 },
  { id: "einstein_gerado26_088", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Mulher, 70 anos de idade, apresenta dispneia progressiva e sinais de congestão sistêmica importante (turgência jugular, edema de membros inferiores, hepatomegalia), com pulso paradoxal e bulhas hipofonéticas. Ecocardiograma mostra espessamento pericárdico e septo em movimento anormal. Qual é o diagnóstico mais provável?", options: ["Pericardite constritiva.", "Miocardite aguda isolada.", "Cardiomiopatia hipertrófica isolada.", "Insuficiência mitral aguda isolada."], correctIndex: 0 },
  { id: "einstein_gerado26_089", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Homem, 45 anos de idade, apresenta sonolência diurna excessiva, roncos altos e pausas respiratórias presenciadas pelo cônjuge durante o sono, obesidade importante. Qual é a hipótese diagnóstica mais provável e o exame confirmatório?", options: ["Síndrome da apneia obstrutiva do sono; polissonografia.", "Asma noturna isolada; espirometria com broncodilatador.", "DPOC; apenas radiografia de tórax.", "Narcolepsia; apenas questionário clínico, sem exame de sono."], correctIndex: 0 },
  { id: "einstein_gerado26_090", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Homem, 50 anos de idade, exposto ocupacionalmente à sílica por 20 anos, apresenta dispneia progressiva e radiografia de tórax com múltiplos nódulos pequenos difusos, predominando em lobos superiores. Qual é o diagnóstico mais provável?", options: ["Silicose.", "Asbestose isolada.", "Sarcoidose pulmonar isolada.", "Tuberculose miliar."], correctIndex: 0 },
  { id: "einstein_gerado26_091", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Mulher, 35 anos de idade, apresenta perda de peso apesar do apetite aumentado, taquicardia, tremores finos e exoftalmia bilateral. TSH suprimido, T4 livre elevado, TRAb positivo. Qual é o diagnóstico mais provável?", options: ["Doença de Graves.", "Tireoidite de Hashimoto.", "Bócio multinodular atóxico.", "Adenoma hipofisário produtor de TSH."], correctIndex: 0 },
  { id: "einstein_gerado26_092", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Homem, 55 anos de idade, diabético tipo 2 de longa data, apresenta úlcera plantar indolor, profunda, com bordas calosas, sem dor associada apesar da profundidade. Monofilamento alterado ao exame de sensibilidade. Qual é a fisiopatologia predominante desse tipo de úlcera?", options: ["Neuropatia periférica diabética predominante, com perda da sensibilidade protetora.", "Isquemia arterial pura, sem componente neuropático.", "Infecção fúngica isolada, sem relação com neuropatia.", "Trauma agudo único, sem relação com o diabetes."], correctIndex: 0 },
  { id: "einstein_gerado26_093", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Homem, 55 anos de idade, apresenta bradicinesia, rigidez em roda denteada e tremor de repouso assimétrico em membro superior direito. Qual é o diagnóstico mais provável e a classe medicamentosa de escolha para controle sintomático inicial?", options: ["Doença de Parkinson idiopática; levodopa/carbidopa.", "Tremor essencial; betabloqueador isolado.", "Paralisia supranuclear progressiva; levodopa contraindicada.", "Demência com corpos de Lewy; anticolinesterásico isolado, sem levodopa."], correctIndex: 0 },
  { id: "einstein_gerado26_094", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Mulher, 30 anos de idade, apresenta fraqueza ascendente progressiva em membros inferiores há 3 dias, evoluindo para membros superiores, com arreflexia e história de infecção gastrointestinal 2 semanas antes. Qual é o diagnóstico mais provável e a conduta?", options: ["Síndrome de Guillain-Barré; imunoglobulina intravenosa ou plasmaférese, com monitorização respiratória.", "Miastenia gravis; piridostigmina isolada, sem monitorização respiratória.", "Esclerose múltipla; corticoide isolado, sem monitorização respiratória.", "Botulismo; apenas observação, sem tratamento específico."], correctIndex: 0 },
  { id: "einstein_gerado26_095", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Nefrologia", text: "Homem, 60 anos de idade, apresenta creatinina sérica em elevação progressiva ao longo de dias, após uso de contraste iodado para tomografia, sem outras causas identificadas. Qual é o diagnóstico mais provável e a principal medida preventiva que deveria ter sido considerada?", options: ["Nefropatia induzida por contraste; hidratação adequada antes e depois do exame em pacientes de risco.", "Necrose tubular aguda por sepse; antibioticoterapia isolada, sem relação com o contraste.", "Glomerulonefrite rapidamente progressiva; biópsia renal imediata, sem relação com o contraste.", "Nefrite intersticial alérgica; suspensão de anti-inflamatório, sem relação com o contraste."], correctIndex: 0 },
  { id: "einstein_gerado26_096", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Geriatria", text: "Mulher, 80 anos de idade, apresenta episódios recorrentes de confusão mental de início agudo e flutuante, associados a infecção urinária, com retorno ao basal cognitivo após tratamento do quadro infeccioso. Qual é o diagnóstico mais provável?", options: ["Delirium precipitado por infecção urinária.", "Demência de Alzheimer em fase inicial.", "Depressão maior com sintomas cognitivos.", "Demência vascular estabelecida."], correctIndex: 0 },
  { id: "einstein_gerado26_097", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Anestesiologia", text: "Paciente será submetido a cirurgia eletiva, ASA II, sem comorbidades relevantes descompensadas. Qual é a conduta apropriada quanto ao jejum pré-operatório para líquidos claros, conforme diretrizes atuais?", options: ["Jejum de líquidos claros de cerca de 2 horas antes da cirurgia é suficiente.", "Jejum absoluto de 12 horas para líquidos claros é sempre necessário.", "Não há necessidade de qualquer jejum antes de cirurgia eletiva.", "Jejum de 24 horas é o padrão recomendado para líquidos claros."], correctIndex: 0 },
  { id: "einstein_gerado26_098", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Ética Médica", text: "Paciente terminal, lúcido, manifesta desejo de não receber medidas de suporte avançado de vida em caso de piora, documentando essa vontade formalmente. Qual é a conduta ética apropriada da equipe médica diante dessa situação?", options: ["Respeitar as diretivas antecipadas de vontade do paciente, registradas enquanto capaz.", "Ignorar o documento e proceder com todas as medidas de suporte avançado, independente da vontade prévia.", "Solicitar autorização judicial obrigatória antes de respeitar qualquer diretiva antecipada.", "Transferir a decisão exclusivamente para os familiares, ignorando a vontade prévia do paciente."], correctIndex: 0 },
  { id: "einstein_gerado26_099", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Psiquiatria", text: "Homem, 35 anos de idade, apresenta pensamentos intrusivos recorrentes sobre contaminação, associados a rituais de lavagem das mãos por horas ao dia, reconhecendo que o comportamento é excessivo, mas incapaz de controlá-lo. Qual é o diagnóstico mais provável e a classe medicamentosa de primeira linha?", options: ["Transtorno obsessivo-compulsivo; inibidor seletivo da recaptação de serotonina em doses geralmente mais altas que na depressão.", "Esquizofrenia; antipsicótico isolado.", "Transtorno de ansiedade generalizada; benzodiazepínico isolado como tratamento de manutenção.", "Transtorno de personalidade obsessivo-compulsiva; psicanálise isolada, sem medicação."], correctIndex: 0 },
  { id: "einstein_gerado26_100", banca: "Einstein", cycle: "Ciclo Clínico", subject: "Hematologia", text: "Homem, 65 anos de idade, apresenta fadiga, linfonodomegalia generalizada indolor e leucocitose importante às custas de linfócitos pequenos e maduros. Imunofenotipagem confirma população clonal de linfócitos B CD5 positivos. Qual é o diagnóstico mais provável?", options: ["Leucemia linfocítica crônica.", "Leucemia mieloide aguda.", "Linfoma de Hodgkin.", "Leucemia mieloide crônica."], correctIndex: 0 },
];
